const items = $input.all();

// Map to array of strings
const availableTimes = items.map(i => {
  if (typeof i.json === "string") return i.json;
  if (i.json.availableTime) return i.json.availableTime;
  return null;
}).filter(Boolean);

// Get requested time and remove seconds if present
const requestedRaw = $('inicio_fluxo').last().json.hora;
const requested = requestedRaw.split(':').slice(0,2).join(':'); // "10:30"

if (availableTimes.includes(requested)) {
  return [{
    status: "sucesso",
    message: `O horário solicitado ${requested} está disponível.`,
    exactMatch: requested
  }];
} else {
  function toMinutes(t) {
    const [h, m] = t.split(":").map(Number);
    return h * 60 + m;
  }

  const requestedM = toMinutes(requested);

  const nextSlots = availableTimes
    .filter(t => toMinutes(t) > requestedM)
    .slice(0, 4);

  return [{
    status: "Horário não disponível",
    message: `O horário solicitado ${requested} não está disponível.`,
    alternatives: nextSlots.length > 0 ? nextSlots : ["No later slots available"]
  }];
}

const horariosDisponiveis = $('Loop Over Items').all();

// Extrai e filtra valores válidos (remove undefined, null, vazio ou objeto vazio)
const horariosDisponiveisUnificadosPorAgenda = [
  ...new Set(
    horariosDisponiveis
      .map(item => item.json?.response?.json)
      .filter(v => v && Object.keys(v).length > 0) // garante que não seja vazio
  )
];

let response;

if (horariosDisponiveisUnificadosPorAgenda.length === 0) {
  response = `Não há horários disponíveis para o dia ${$('SELECT sessao_agendamento').last().json.data_agendamento}.`;
} else {
  response = `Os horários disponíveis para o dia ${$('SELECT sessao_agendamento').last().json.data_agendamento} são: ${JSON.stringify(horariosDisponiveisUnificadosPorAgenda)}.`;
}

return [{ response }];

